```csharp
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity
{
    public class PaginatedList<T> : List<T>
    {
        public int PageIndex { get; private set; }
        public int TotalPages { get; private set; }

        public PaginatedList(List<T> items, int count, int pageIndex, int pageSize)
        {
            PageIndex = pageIndex;
            TotalPages = (int)Math.Ceiling(count / (double)pageSize);

            this.AddRange(items);
        }

        public bool HasPreviousPage => PageIndex > 1;

        public bool HasNextPage => PageIndex < TotalPages;

        public static PaginatedList<T> Create(IQueryable<T> source, int pageIndex, int pageSize)
        {
            var count = source.Count();
            var items = source.Skip((pageIndex - 1) * pageSize).Take(pageSize).ToList();
            return new PaginatedList<T>(items, count, pageIndex, pageSize);
        }
    }
}
```

**Public API Surface:**
- **Constructor:** `PaginatedList(List<T> items, int count, int pageIndex, int pageSize)`
- **Properties:**
  - `PageIndex { get; }` - Current page number (1-based)
  - `TotalPages { get; }` - Calculated total pages
  - `HasPreviousPage { get; }` - Boolean if page > 1
  - `HasNextPage { get; }` - Boolean if page < TotalPages
- **Methods:**
  - `static Create(IQueryable<T> source, int pageIndex, int pageSize)` - Factory method

**Dependencies:**
- Extends `List<T>` directly
- Uses LINQ `Count()`, `Skip()`, `Take()`, `ToList()`

**Edge Cases to Test:**
- `pageSize = 0` → Division by zero in `Math.Ceiling()`
- `pageIndex = 0` → HasPreviousPage returns false (correct)
- `count = 0` → TotalPages = 0
- `pageIndex > TotalPages` → HasNextPage returns false (correct)
- Single item with pageSize 1
- Negative counts or page numbers

