**Complete Content:**
```csharp
using System;
using System.Collections.Concurrent;
using ContosoUniversity.Models;

namespace ContosoUniversity.Services
{
    public class NotificationService : IDisposable
    {
        // Static shared queue across application instances (simple in-memory alternative to MSMQ)
        private static readonly ConcurrentQueue<Notification> _queue = new();
        private static readonly int _maxQueueLength = 500; // basic cap to prevent unbounded growth

        public NotificationService()
        {
            // No initialization required for in-memory queue
        }

        public void SendNotification(string entityType, string entityId, EntityOperation operation, string userName = null)
        {
            SendNotification(entityType, entityId, null, operation, userName);
        }

        public void SendNotification(string entityType, string entityId, string entityDisplayName, EntityOperation operation, string userName = null)
        {
            try
            {
                var notification = new Notification
                {
                    EntityType = entityType,
                    EntityId = entityId,
                    Operation = operation.ToString(),
                    Message = GenerateMessage(entityType, entityId, entityDisplayName, operation),
                    CreatedAt = DateTime.Now,
                    CreatedBy = userName ?? "System",
                    IsRead = false
                };

                _queue.Enqueue(notification);

                // Enforce max queue length (best-effort)
                while (_queue.Count > _maxQueueLength && _queue.TryDequeue(out _)) { }
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"Failed to enqueue notification: {ex.Message}");
            }
        }

        public Notification ReceiveNotification()
        {
            try
            {
                return _queue.TryDequeue(out var notification) ? notification : null;
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"Failed to receive notification: {ex.Message}");
                return null;
            }
        }

        public void MarkAsRead(int notificationId)
        {
            // No-op for in-memory implementation (persistence not implemented)
        }

        private string GenerateMessage(string entityType, string entityId, string entityDisplayName, EntityOperation operation)
        {
            var displayText = !string.IsNullOrWhiteSpace(entityDisplayName)
                ? $"{entityType} '{entityDisplayName}'"
                : $"{entityType} (ID: {entityId})";

            return operation switch
            {
                EntityOperation.CREATE => $"New {displayText} has been created",
                EntityOperation.UPDATE => $"{displayText} has been updated",
                EntityOperation.DELETE => $"{displayText} has been deleted",
                _ => $"{displayText} operation: {operation}"
            };
        }

        public void Dispose()
        {
            // Nothing to dispose for in-memory queue
        }
    }
}
```

**Public API Surface:**
- **Constructor:** `NotificationService()` - no parameters
- **Methods:**
  - `void SendNotification(string entityType, string entityId, EntityOperation operation, string userName = null)`
  - `void SendNotification(string entityType, string entityId, string entityDisplayName, EntityOperation operation, string userName = null)`
  - `Notification ReceiveNotification()` - returns null if queue empty
  - `void MarkAsRead(int notificationId)` - no-op, not implemented
  - `void Dispose()` - implements IDisposable
- **Implements:** IDisposable

**Key Design Patterns:**
- **Static ConcurrentQueue:** Shared across all instances (not thread-safe for single-instance operations)
- **Overloaded methods:** One with displayName, one without
- **Message generation:** Uses switch expression for CREATE/UPDATE/DELETE
- **Max queue length:** 500 notifications (best-effort enforcement)

**Critical Behaviors & Edge Cases:**
1. **Static queue:** All instances share the same queue (application-wide)
2. **In-memory only:** No persistence; notifications lost on app restart
3. **MarkAsRead is no-op:** Not implemented, no persistence
4. **Exception handling:** All public methods catch exceptions and log to Debug, return gracefully
5. **DateTime.Now:** Uses local time, not UTC
6. **Queue overflow:** Dequeues oldest notifications when exceeding 500 (best-effort, race conditions possible)
7. **Thread safety:** ConcurrentQueue is thread-safe, but max-length enforcement is not

**What Needs Mocking:**
- DateTime (for testing CreatedAt timestamps)
- ConcurrentQueue behavior (dequeue order)
- Exception scenarios

**Testing Considerations:**
- Queue is static and shared; tests may interfere with each other
- Need to clear queue between tests or use isolation
- Test max-length enforcement (edge case at 500)
- Test message generation for different operations
- Test exception handling and Debug output
- Test null/empty entityDisplayName handling

