        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;

        public CoursesControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns(Path.Combine(Directory.GetCurrentDirectory(), "wwwroot_test"));
            _mockEnv.Setup(e => e.ContentRootPath).Returns(Directory.GetCurrentDirectory());
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Department SeedDepartment()
        {
            var dept = new Department
            {
                Name = "Engineering",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();
            return dept;
        }

        private Course SeedCourse(Department dept = null)
        {
            dept ??= SeedDepartment();
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();
            return course;
        }

        private static Mock<IFormFile> CreateMockFormFile(string fileName, long size)
        {
            var mock = new Mock<IFormFile>();
            mock.Setup(f => f.FileName).Returns(fileName);
            mock.Setup(f => f.Length).Returns(size);
            mock.Setup(f => f.CopyTo(It.IsAny<Stream>()));
            return mock;
        }

