                DepartmentID = dept.DepartmentID
            };
            var mockFile = CreateMockFormFile("test.jpg", 1024);

            // The actual file write will throw because the directory doesn't exist under WebRootPath
            // but the key test is the validation flow, so we mock the env to use content root
            _mockEnv.Setup(e => e.WebRootPath).Returns((string)null);

