            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Theory]
        [InlineData(".jpg")]
        [InlineData(".jpeg")]
        [InlineData(".png")]
        [InlineData(".gif")]
        [InlineData(".bmp")]
        public void Create_POST_ValidImageExtensions_AreAccepted(string extension)
        {
            var dept = SeedDepartment();
            var course = new Course
            {
                CourseID = 2000 + extension.GetHashCode() % 1000,
                Title = "Physics",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            var mockFile = CreateMockFormFile($"test{extension}", 1024);
            _mockEnv.Setup(e => e.WebRootPath).Returns((string)null);

            var result = _controller.Create(course, mockFile.Object);
            // Should not have the file extension error
            Assert.False(_controller.ModelState.ContainsKey("teachingMaterialImage") &&
                _controller.ModelState["teachingMaterialImage"].Errors.Any(e => e.ErrorMessage.Contains("valid image")));
        }

