            {
                InstructorID = instructor.ID,
                CourseID = course.CourseID
            };
            _context.CourseAssignments.Add(ca);
            _context.SaveChanges();

            // Reload instructor with relationships
            _context.Entry(instructor).Collection(i => i.CourseAssignments).Load();

            return (instructor, course, dept);
