        [Theory]
        [InlineData("Smith", "John", "Smith, John")]
        [InlineData("O'Brien", "Mary", "O'Brien, Mary")]
        [InlineData("", "", ", ")]
        [InlineData("LastOnly", null, "LastOnly, ")]
        public void FullName_ReturnsLastNameCommaFirstName(string lastName, string firstName, string expected)
        {
            var person = new TestPerson { LastName = lastName, FirstMidName = firstName };
            Assert.Equal(expected, person.FullName);
        }

