using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;
using System.Threading.Tasks;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from the static queue
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain the static queue after each test to reduce cross-test interference
            while (_service.ReceiveNotification() != null) { }
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_Overload1_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.False(notification.IsRead);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_Overload2_WithDisplayName_EnqueuesNotification()
        {
            _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.UPDATE, "Admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Course", notification.EntityType);
            Assert.Equal("1050", notification.EntityId);
            Assert.Equal("UPDATE", notification.Operation);
            Assert.Equal("Admin", notification.CreatedBy);
            Assert.Contains("Chemistry", notification.Message);
        }

        [Fact]
        public void SendNotification_WithUserName_SetsCreatedBy()
        {
            _service.SendNotification("Student", "1", "John", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();
            Assert.Equal("TestUser", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("System", notification.CreatedBy);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "created")]
        [InlineData(EntityOperation.UPDATE, "updated")]
        [InlineData(EntityOperation.DELETE, "deleted")]
        public void SendNotification_GeneratesCorrectMessage_ForOperation(EntityOperation operation, string expectedVerb)
        {
            _service.SendNotification("Student", "1", "John Doe", operation);

            var notification = _service.ReceiveNotification();
            Assert.Contains(expectedVerb, notification.Message);
            Assert.Contains("John Doe", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void SendNotification_WithDisplayName_UsesNameInMessage()
        {
            _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Contains("Chemistry", notification.Message);
            Assert.DoesNotContain("ID:", notification.Message);
        }

        [Fact]
        public void ReceiveNotification_ReturnsNull_WhenQueueEmpty()
        {
            var notification = _service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_ReturnsInFIFOOrder()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.Equal("Student", first.EntityType);
            Assert.Equal("Course", second.EntityType);
        }

        [Fact]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var first = _service.ReceiveNotification();
            Assert.NotNull(first);

            var second = _service.ReceiveNotification();
            Assert.Null(second);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now.AddSeconds(-1);
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now.AddSeconds(1);

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void SendNotification_SetsIsReadToFalse()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow_WithNonExistentId()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(999));
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            var service = new NotificationService();
            service.Dispose();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void ConcurrentAccess_DoesNotThrow()
        {
            var tasks = new Task[10];
            for (int i = 0; i < 10; i++)
            {
                int idx = i;
                tasks[i] = Task.Run(() =>
                {
                    for (int j = 0; j < 50; j++)
                    {
                        _service.SendNotification("Entity", $"{idx}_{j}", EntityOperation.CREATE);
                        _service.ReceiveNotification();
                    }
                });
            }

            var exception = Record.Exception(() => Task.WaitAll(tasks));
            Assert.Null(exception);
        }
    }
}

